############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(A.1.7.110) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextForm.pl", "contextRationalFunction.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Numeric"); Context()->variables->are(a=>'Real'); $p = random(1,9,1); $q = random(1,9,2); $p2 = 2*$p; $num = (2*$p+$q); $left = Formula("$p/a"); $right = Formula("$q/(2a)"); $expression = $left + $right; Context("RationalFunction-Strict"); Context()->variables->are(a=>'Real'); $answer = Formula("$num/(2a)");
############################################################ # Body ############################################################
BEGIN_PGML Given that [`a\neq0\text{,}`] simplify [`\displaystyle{}[$expression]\text{.}`]
[_]{$answer}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION Since the fractions don't have the same denominator, we have to make them have like denominators. Multiply the first fraction by [`\frac{2}{2}\text{.}`]
[```\newcommand{\amp}{&} \begin{aligned} [$expression] \amp = [$left]\cdot \frac{2}{2} + [$right]\\ \amp = \frac{[$p2]}{2a} + [$right]\\ \amp = [$answer] \end{aligned} ```]
END_PGML_SOLUTION
############################################################ # End Problem ############################################################
ENDDOCUMENT();
